+func nonEmptyLines(s string) []string {
+	lines := strings.Split(strings.TrimSpace(s), "\n")
+	var out []string
+	for _, line := range lines {
+		line = strings.TrimSpace(line)
+		if line != "" {
+			out = append(out, line)
+		}
+	}
+	return out
+}

