+	}
+}
+
+// assertChildCounter verifies the last_child value in child_counters.
+func (te *testEnv) assertChildCounter(t *testing.T, ctx context.Context, parentID string, wantLastChild int) {
+	t.Helper()
+	var lastChild int
+	te.queryScalar(t, ctx,
