+			t.Fatalf("AddLabel: %v", err)
+		}
+		if err := te.store.Commit(ctx, "add labels"); err != nil {
+			t.Fatalf("Commit: %v", err)
+		}
+
+		got, err := te.store.GetIssue(ctx, "il-labeled")
+		if err != nil {
+			t.Fatalf("GetIssue: %v", err)
+		}
